import './Collapse.scss';

import { classNames } from ':helpers/classnames';
import { Icons } from '@beeline/design-tokens/js/iconfont/icons';
import type { FC, MouseEventHandler } from 'react';
import React, { useEffect, useId, useState } from 'react';

import { Icon } from '../Icon';
import { Link } from '../Link';
import type { CollapseProps } from './Collapse.types';

export const Collapse: FC<CollapseProps> = ({
	expanded: expandedProp,
	defaultExpanded = false,
	onToggle,
	labelCollapsed = 'Развернуть',
	labelExpanded = 'Свернуть',
	size = 'medium',
	children,
	className,
	triggerClassName,
	contentClassName,
	dataTestId = 'Collapse',
	onExpand,
	onCollapse,
}) => {
	const contentId = useId();
	const [internalExpanded, setInternalExpanded] = useState(defaultExpanded);

	const isControlled = expandedProp !== undefined;
	const expanded = isControlled ? expandedProp : internalExpanded;

	useEffect(() => {
		if (isControlled && expandedProp !== internalExpanded) {
			setInternalExpanded(expandedProp);
		}
	}, [isControlled, expandedProp, internalExpanded]);

	const handleClick: MouseEventHandler<HTMLElement> = event => {
		const newExpanded = !expanded;

		if (!isControlled) {
			setInternalExpanded(newExpanded);
		}

		onToggle?.(newExpanded, event as React.MouseEvent<HTMLElement>);

		if (newExpanded) {
			onExpand?.(event as React.MouseEvent<HTMLElement>);
		} else {
			onCollapse?.(event as React.MouseEvent<HTMLElement>);
		}
	};

	const label = expanded ? labelExpanded : labelCollapsed;
	const iconSize = size === 'large' ? 'medium' : 'small';
	const endIcon = expanded ? (
		<Icon iconName={Icons.ArrowUp} size={iconSize} />
	) : (
		<Icon iconName={Icons.ArrowDown} size={iconSize} />
	);

	return (
		<div data-testid={dataTestId} className={classNames('dsb_collapse', className)}>
			<Link
				onClick={handleClick}
				size={size}
				endIcon={endIcon}
				className={classNames('dsb_collapse-trigger', triggerClassName)}
				aria-expanded={expanded}
				aria-controls={children !== undefined ? contentId : undefined}
			>
				{label}
			</Link>
			{children !== undefined && (
				<div
					id={contentId}
					className={classNames(
						'dsb_collapse-content',
						expanded ? 'dsb_collapse-content__expanded' : 'dsb_collapse-content__collapsed',
						contentClassName,
					)}
				>
					{children}
				</div>
			)}
		</div>
	);
};

Collapse.displayName = 'Collapse';
